# oncall_health_report.py — weekly on-call health summary
from dataclasses import dataclass
import requests

@dataclass
class OnCallHealthSummary:
    engineer: str
    rotation_week: str
    total_pages: int
    after_hours_pages: int
    p0_pages: int
    mtta_minutes: float
    actionable_rate: float   # 0.0 - 1.0

    @property
    def status(self) -> str:
        if self.total_pages > 10 or self.after_hours_pages > 5:
            return "DANGER"
        if self.total_pages > 5 or self.after_hours_pages > 2:
            return "CAUTION"
        return "HEALTHY"

def generate_health_report(summaries: list[OnCallHealthSummary]) -> str:
    lines = ["# On-Call Health Report\n"]
    for s in summaries:
        lines.append(f"**{s.engineer}** (week {s.rotation_week}): {s.status}")
        lines.append(f"  Pages: {s.total_pages} total, {s.after_hours_pages} after-hours, {s.p0_pages} P0")
        lines.append(f"  MTTA: {s.mtta_minutes:.1f} min | Actionable: {s.actionable_rate:.0%}\n")
    return "\n".join(lines)

# oncall_escalation.py — auto-escalate when health is DANGER for 2 consecutive weeks
from collections import defaultdict

def check_escalation_needed(
    history: list[OnCallHealthSummary],
    consecutive_danger_threshold: int = 2,
) -> list[str]:
    """Return engineer names who need immediate rotation relief."""
    danger_streaks: dict[str, int] = defaultdict(int)
    for summary in sorted(history, key=lambda s: s.rotation_week):
        if summary.status == "DANGER":
            danger_streaks[summary.engineer] += 1
        else:
            danger_streaks[summary.engineer] = 0  # reset streak

    return [
        eng
        for eng, streak in danger_streaks.items()
        if streak >= consecutive_danger_threshold
    ]

